import React, { useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";

const cities = [
  "Trivandrum",
  "Kochi",
  "Bangalore",
  "Chennai",
  "Hyderabad",
  "Coimbatore",
  "Madurai",
  "Mysore"
];

const Home: React.FC = () => {
  const [departureCity, setDepartureCity] = useState("");
  const [arrivalCity, setArrivalCity] = useState("");
  const [date, setDate] = useState("");
  const navigate = useNavigate();

  const canSearch = useMemo(() => {
    return Boolean(departureCity && arrivalCity && date && departureCity !== arrivalCity);
  }, [departureCity, arrivalCity, date]);

  const handleSubmit = (event: React.FormEvent) => {
    event.preventDefault();

    const query = new URLSearchParams({
      departureCity,
      arrivalCity,
      date
    }).toString();

    navigate(`/buses?${query}`);
  };

  return (
    <section className="grid gap-8 lg:grid-cols-[1.1fr_1fr] lg:items-center">
      <div>
        <p className="mb-2 text-sm font-semibold uppercase tracking-wider text-blue-700">Smart Bus Booking</p>
        <h1 className="text-3xl font-bold leading-tight text-slate-900 sm:text-4xl">
          Find the best bus route for your next trip.
        </h1>
        <p className="mt-4 max-w-lg text-slate-600">
          Compare timings, seat types, AC options, and prices in one place. Book your seats in a few clicks.
        </p>
      </div>

      <form onSubmit={handleSubmit} className="rounded-2xl bg-white p-6 shadow-travel ring-1 ring-slate-200 sm:p-8">
        <h2 className="mb-5 text-xl font-semibold text-slate-900">Search Buses</h2>

        <div className="space-y-4">
          <label className="block text-sm font-medium text-slate-700">
            Departure
            <select
              className="mt-1 w-full rounded-lg border border-slate-300 px-3 py-2 outline-none focus:border-blue-500"
              value={departureCity}
              onChange={(e) => setDepartureCity(e.target.value)}
              required
            >
              <option value="">Select departure city</option>
              {cities.map((city) => (
                <option key={`dep-${city}`} value={city}>
                  {city}
                </option>
              ))}
            </select>
          </label>

          <label className="block text-sm font-medium text-slate-700">
            Arrival
            <select
              className="mt-1 w-full rounded-lg border border-slate-300 px-3 py-2 outline-none focus:border-blue-500"
              value={arrivalCity}
              onChange={(e) => setArrivalCity(e.target.value)}
              required
            >
              <option value="">Select arrival city</option>
              {cities.map((city) => (
                <option key={`arr-${city}`} value={city}>
                  {city}
                </option>
              ))}
            </select>
          </label>

          <label className="block text-sm font-medium text-slate-700">
            Date
            <input
              type="date"
              className="mt-1 w-full rounded-lg border border-slate-300 px-3 py-2 outline-none focus:border-blue-500"
              value={date}
              onChange={(e) => setDate(e.target.value)}
              required
            />
          </label>

          <button
            type="submit"
            className="w-full rounded-lg bg-blue-600 px-4 py-2.5 font-semibold text-white transition hover:bg-blue-700 disabled:cursor-not-allowed disabled:bg-blue-300"
            disabled={!canSearch}
          >
            Search
          </button>
        </div>
      </form>
    </section>
  );
};

export default Home;
